mapper.select:
SELECT ptr.id, ptr.transfer_no, ptr.patient_id, ptr.patient_name, p.patient_no, ptr.from_ward_id, ptr.from_ward_name, ptr.from_bed_no, ptr.to_ward_id, ptr.to_ward_name, ptr.to_bed_no, ptr.operator_id, ptr.operator_name, ptr.transfer_time, ptr.remark FROM patient_transfer_record ptr LEFT JOIN patient p ON ptr.patient_id = p.id WHERE ptr.deleted = 0
AND ptr.patient_id = #{patientId}
AND ptr.from_ward_id = #{fromWardId}
AND ptr.to_ward_id = #{toWardId}
AND ptr.patient_name LIKE CONCAT('%', #{patientName}, '%')
ORDER BY ptr.transfer_time DESC
